import hashlib
import secrets
from cryptography.fernet import Fernet

def encrypt_user_data(data, encryption_key=None):
    """
    Encrypts sensitive user data before storing in database
    """
    if encryption_key is None:
        # Generate a new encryption key if none provided
        encryption_key = Fernet.generate_key()
    
    fernet = Fernet(encryption_key)
    
    # Convert data to bytes if it's not already
    if isinstance(data, str):
        data = data.encode('utf-8')
    
    # Encrypt the data
    encrypted_data = fernet.encrypt(data)
    
    return encrypted_data, encryption_key

def hash_password(password, salt=None):
    """
    Hashes a password with salt for secure storage
    """
    if salt is None:
        salt = secrets.token_hex(16)
    
    # Combine password and salt
    salted_password = password + salt
    
    # Hash the salted password
    hashed = hashlib.sha256(salted_password.encode('utf-8')).hexdigest()
    
    return hashed, salt

def encrypt_sensitive_fields(user_data):
    """
    Encrypts sensitive fields in user data
    """
    encrypted_data = {}
    encryption_key = Fernet.generate_key()
    
    sensitive_fields = ['password', 'ssn', 'credit_card', 'phone']
    
    for field, value in user_data.items():
        if field in sensitive_fields:
            encrypted_value, _ = encrypt_user_data(value, encryption_key)
            encrypted_data[field] = encrypted_value
        else:
            encrypted_data[field] = value
    
    return encrypted_data, encryption_key